final:
module RefModule(I, O, S0, S1);input [3:0] I;
  output O;
  input S0, S1;

  reg [3:0] final_sig;
  always @ (S0, S1, I) begin
    case ({S1, S0})
      2'b00: final_sig = I[0];
      2'b01: final_sig = I[1];
      2'b10: final_sig = I[2];
      2'b11: final_sig = I[3];
    endcase
  end

  assign O = final_sig;
endmodule
